def solve(nums: Array[Long]): Long = {
  import scala.collection.mutable

  val n = nums.length
  val dp = Array.fill(n + 1, 3)(0L) // dp[i][j] represents the maximum value for first i elements with j being the current state (0: A, 1: B, 2: C)

  for (i <- 1 to n) {
    for (j <- 0 to 2) {
      val currentNum = nums(i - 1)
      // Case 1: assign current number to A
      val xorA = dp(i - 1)(0) ^ currentNum
      dp(i)(0) = math.max(dp(i)(0), xorA)
      // Case 2: assign current number to B
      val andB = if (dp(i - 1)(1) == 0L) currentNum else dp(i - 1)(1) & currentNum
      dp(i)(1) = math.max(dp(i)(1), andB)
      // Case 3: assign current number to C
      val xorC = dp(i - 1)(2) ^ currentNum
      dp(i)(2) = math.max(dp(i)(2), xorC)
    }
  }

  math.max(dp(n)(0), dp(n)(1), dp(n)(2))
}
